// frontend/src/components/jobs/JobDetails.js
import React, { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import api from '../../services/api';
import { useAuth } from '../../contexts/AuthContext';
import './JobDetails.css';

const JobDetails = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user, isAuthenticated } = useAuth();

    const [job, setJob] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [applying, setApplying] = useState(false);
    const [applicationData, setApplicationData] = useState({
        proposed_rate: '',
        message: '',
        estimated_completion_time: ''
    });

    useEffect(() => {
        loadJobDetails();
    }, [id]);

    const loadJobDetails = async () => {
        setLoading(true);
        try {
            const response = await api.get(`/jobs/${id}`);
            if (response.data.success) {
                setJob(response.data.data);
            } else {
                setError('Job not found');
            }
        } catch (error) {
            console.error('Error loading job:', error);
            setError('Failed to load job details');
        } finally {
            setLoading(false);
        }
    };

    const handleApply = async (e) => {
        e.preventDefault();
        if (!isAuthenticated) {
            navigate('/login', { state: { from: `/jobs/${id}` } });
            return;
        }

        setApplying(true);
        setError('');

        try {
            const response = await api.post(`/jobs/${id}/apply`, applicationData);
            if (response.data.success) {
                alert('Application submitted successfully!');
                loadJobDetails(); // Reload to show updated status
            } else {
                setError(response.data.message || 'Failed to apply');
            }
        } catch (error) {
            console.error('Apply error:', error);
            setError('Network error. Please try again.');
        } finally {
            setApplying(false);
        }
    };

    const handleInputChange = (e) => {
        setApplicationData({
            ...applicationData,
            [e.target.name]: e.target.value
        });
    };

    const formatDate = (dateString) => {
        const date = new Date(dateString);
        return date.toLocaleDateString('en-ZA', {
            day: 'numeric',
            month: 'short',
            year: 'numeric'
        });
    };

    if (loading) {
        return <div className="loading-spinner">Loading job details...</div>;
    }

    if (error || !job) {
        return (
            <div className="error-container">
                <h2>Error</h2>
                <p>{error || 'Job not found'}</p>
                <Link to="/jobs" className="btn-primary">Browse Jobs</Link>
            </div>
        );
    }

    const hasApplied = job.applications?.some(app => app.worker_id === user?.id);
    const isOwner = job.client_id === user?.id;

    return (
        <div className="job-details-container">
            <div className="job-details">
                {/* Header */}
                <div className="job-header">
                    <h1>{job.title}</h1>
                    <div className="job-meta">
                        <span className="meta-item">📋 {job.job_code}</span>
                        <span className="meta-item">📍 {job.township}</span>
                        <span className="meta-item">📅 Posted {formatDate(job.created_at)}</span>
                        <span className={`job-status status-${job.status}`}>
                            {job.status}
                        </span>
                    </div>
                </div>

                {/* Budget Card */}
                <div className="budget-card">
                    <div className="budget-info">
                        <h3>Budget Range</h3>
                        <div className="budget-amount">
                            R {job.budget_min} - R {job.budget_max}
                        </div>
                    </div>
                    {job.estimated_hours && (
                        <div className="budget-note">
                            Estimated {job.estimated_hours} hours
                        </div>
                    )}
                </div>

                {/* Description */}
                <div className="job-description">
                    <h2>Description</h2>
                    <p>{job.description}</p>
                </div>

                {/* Details Grid */}
                <div className="details-grid">
                    {job.category && (
                        <div className="detail-card">
                            <h3>Category</h3>
                            <div className="detail-content">{job.category}</div>
                        </div>
                    )}
                    {job.urgency && (
                        <div className="detail-card">
                            <h3>Urgency</h3>
                            <div className="detail-content">
                                {job.urgency.charAt(0).toUpperCase() + job.urgency.slice(1)}
                            </div>
                        </div>
                    )}
                    {job.preferred_date && (
                        <div className="detail-card">
                            <h3>Preferred Date</h3>
                            <div className="detail-content">{formatDate(job.preferred_date)}</div>
                        </div>
                    )}
                    {job.preferred_time && (
                        <div className="detail-card">
                            <h3>Preferred Time</h3>
                            <div className="detail-content">{job.preferred_time}</div>
                        </div>
                    )}
                </div>

                {/* Materials */}
                {job.materials_provided && (
                    <div className="materials-section">
                        <h2>Materials Provided</h2>
                        <p className="materials-provided">✓ Yes, materials will be provided</p>
                        {job.materials_description && (
                            <p>{job.materials_description}</p>
                        )}
                    </div>
                )}

                {/* Safety Requirements */}
                {job.safety_requirements && (
                    <div className="materials-section">
                        <h2>Safety Requirements</h2>
                        <p>{job.safety_requirements}</p>
                    </div>
                )}

                {/* Client Info */}
                <div className="client-card">
                    <div className="client-info">
                        <h3>Posted by</h3>
                        <h2>{job.client_name}</h2>
                        <p className="client-location">📍 {job.client_township || job.township}</p>
                    </div>
                    {isAuthenticated && !isOwner && (
                        <button className="btn-contact">
                            Message Client
                        </button>
                    )}
                </div>

                {/* Applications Section (for job owner) */}
                {isOwner && job.applications && job.applications.length > 0 && (
                    <div className="applications-section">
                        <h2>Applications ({job.applications.length})</h2>
                        <div className="applications-list">
                            {job.applications.map(app => (
                                <div key={app.id} className="application-item">
                                    <div className="application-header">
                                        <Link to={`/workers/${app.worker_id}`} className="worker-name">
                                            {app.worker_name}
                                        </Link>
                                        <span className="application-rate">
                                            R {app.proposed_rate}
                                        </span>
                                    </div>
                                    {app.message && (
                                        <p className="application-message">{app.message}</p>
                                    )}
                                    <div className="application-footer">
                                        <span className="application-date">
                                            Applied: {formatDate(app.created_at)}
                                        </span>
                                        <div>
                                            <button className="btn-accept">Accept</button>
                                            <button className="btn-reject">Decline</button>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* Apply Section (for workers) */}
                {!isOwner && user?.user_type === 'worker' && job.status === 'posted' && (
                    <div className="apply-section">
                        <h2>Apply for this Job</h2>

                        {hasApplied ? (
                            <div className="already-applied">
                                You have already applied for this job. Check your dashboard for status.
                            </div>
                        ) : (
                            <form onSubmit={handleApply} className="apply-form">
                                <div className="form-group">
                                    <label>Your Proposed Rate (R) *</label>
                                    <input
                                        type="number"
                                        name="proposed_rate"
                                        value={applicationData.proposed_rate}
                                        onChange={handleInputChange}
                                        placeholder={`Between R${job.budget_min} - R${job.budget_max}`}
                                        min={job.budget_min}
                                        max={job.budget_max}
                                        required
                                    />
                                </div>

                                <div className="form-group">
                                    <label>Message to Client</label>
                                    <textarea
                                        name="message"
                                        value={applicationData.message}
                                        onChange={handleInputChange}
                                        placeholder="Tell the client why you're the best person for this job..."
                                        rows="3"
                                    />
                                </div>

                                <div className="form-group">
                                    <label>Estimated Completion Time</label>
                                    <input
                                        type="text"
                                        name="estimated_completion_time"
                                        value={applicationData.estimated_completion_time}
                                        onChange={handleInputChange}
                                        placeholder="e.g., 3 hours, tomorrow, by Friday"
                                    />
                                </div>

                                <button 
                                    type="submit" 
                                    className="btn-submit"
                                    disabled={applying}
                                >
                                    {applying ? 'Submitting...' : 'Submit Application'}
                                </button>
                            </form>
                        )}
                    </div>
                )}

                {/* Login Prompt for non-authenticated users */}
                {!isAuthenticated && job.status === 'posted' && (
                    <div className="apply-section">
                        <p>Want to apply for this job?</p>
                        <Link to="/login" className="btn-primary">
                            Sign in to Apply
                        </Link>
                    </div>
                )}
            </div>
        </div>
    );
};

export default JobDetails;
